        if (!ShouldAppendToUndoBuffer())
            return;

        UndoBuffer.RegisterManagedOperation(recordType, commit, rollback);
    }

    public void TrackVersionedAction<TPayload>(
        UndoRecordType recordType,
        TPayload payload,
        Action<TPayload> commit,
        Action<TPayload> rollback)
    {
        if (!ShouldAppendToUndoBuffer())
            return;

        UndoBuffer.RegisterManagedOperation(recordType, payload, commit, rollback);
    }

    public void TrackVersionedAction<TPayload>(
        UndoRecordType recordType,
        TPayload payload)
        where TPayload : IManagedUndoPayload
    {
        if (!ShouldAppendToUndoBuffer())
            return;

        UndoBuffer.RegisterManagedOperation(recordType, payload);
    }

    public void TrackVersionedRowAction(
        UndoRecordType recordType,
        IRawUndoReplayTarget target,
        int rowIndex,
        ReadOnlySpan<byte> payload = default)
    {
        if (!ShouldAppendToUndoBuffer())
            return;

        UndoBuffer.RegisterVersionedRowOperation(recordType, target, this, rowIndex, payload);
    }

    public void Commit(ulong commitTS)
