        CommitTS = commitTS;
    }

    internal void CaptureRecoveryOffsets(ulong walOffset, ulong graphLogOffset)
    {
        RecoveryWalOffset = walOffset;
        RecoveryGraphLogOffset = graphLogOffset;
    }

    internal void CommitVersionedChanges()
    {
        UndoBuffer?.CommitRawOperations(CommitTS);
        UndoBuffer?.CommitManagedOperations();
        UndoBuffer?.Dispose();
        _versionedParticipants.Clear();
    }

    public void Rollback()
    {
    }

    internal void RollbackVersionedChanges()
    {
        UndoBuffer?.RollbackRawOperations();
        UndoBuffer?.RollbackManagedOperations();
        UndoBuffer?.Dispose();
        _versionedParticipants.Clear();
    }

    public static readonly Transaction DUMMY_TRANSACTION = new Transaction(TransactionType.DUMMY);
    public static readonly Transaction DUMMY_CHECKPOINT_TRANSACTION = new Transaction(TransactionType.CHECKPOINT);
}
